class Solution {
public:
    int minInsertions(string s) {
        int ans = 0, cnt = 0;
        for (char c : s) {
            if (c == '(') {
                if (cnt % 2) {
                    ans++;
                }
                cnt = 0;
            } else {
                cnt++;
                if (cnt == 2) {
                    cnt = 0;
                }
            }
        }
        return ans + cnt;
    }
};
